// Fast lookup by partial company name (case-insensitive)
export function findExhibitor(query: string): Exhibitor | undefined {
  const q = query.toLowerCase();
  return asco2026Exhibitors.find(
    (e) => e.name.toLowerCase().includes(q) || q.includes(e.name.toLowerCase())
  );
}

// Find booth number for a company name mention — used in broadcast scripts
export function getBoothContext(companyName: string): string | null {
  const match = findExhibitor(companyName);
  if (!match) return null;
  const cats = match.categories.slice(0, 2).join(" and ");
  const catNote = cats ? ` (${cats})` : "";
  return `${match.name} is at booth ${match.booth}${catNote}.`;
}

// All featured exhibitors — used for scheduled booth-tour segments
export const featuredExhibitors = asco2026Exhibitors.filter((e) => e.featured);

// First-time exhibitors — good for novelty segments
export const firstTimeExhibitors = asco2026Exhibitors.filter((e) => e.firstTime);
